PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE `User` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `openid` VARCHAR(255) NOT NULL UNIQUE, `nickname` VARCHAR(255), `role` VARCHAR(255) DEFAULT 'user', `avatarUrl` VARCHAR(255), `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `Counselor` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `name` VARCHAR(255) NOT NULL, `type` VARCHAR(255) NOT NULL DEFAULT '内部', `sub_type` VARCHAR(255) NOT NULL DEFAULT '', `booking_price` FLOAT NOT NULL DEFAULT '0', `booking_multi_price` FLOAT NOT NULL DEFAULT '0', `note` VARCHAR(255) NOT NULL DEFAULT '', `status` INTEGER NOT NULL DEFAULT 1, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `Room` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `name` VARCHAR(255) NOT NULL, `type` VARCHAR(255) NOT NULL DEFAULT '咨询室', `isAvailable` TINYINT(1) DEFAULT 1, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `Booking` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `booking_date` VARCHAR(255) NOT NULL, `start_time_slot` INTEGER NOT NULL, `start_time` VARCHAR(255) NOT NULL, `end_time_slot` INTEGER NOT NULL, `end_time` VARCHAR(255) NOT NULL, `counselor_id` INTEGER NOT NULL REFERENCES `Counselor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE, `booker_name` VARCHAR(255) NOT NULL, `booker_type` VARCHAR(255) NOT NULL, `booking_fee` FLOAT NOT NULL DEFAULT '0', `status` TEXT DEFAULT 'booked', `user_id` VARCHAR(255) NOT NULL, `room_id` INTEGER NOT NULL REFERENCES `Room` (`id`) ON DELETE CASCADE ON UPDATE CASCADE, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `RecurringRule` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `day_of_week` INTEGER NOT NULL, `start_time` VARCHAR(255) NOT NULL, `start_time_slot` INTEGER NOT NULL, `end_time` VARCHAR(255) NOT NULL, `end_time_slot` INTEGER NOT NULL, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, `counselor_id` INTEGER REFERENCES `Counselor` (`id`) ON DELETE SET NULL ON UPDATE CASCADE, `room_id` INTEGER REFERENCES `Room` (`id`) ON DELETE SET NULL ON UPDATE CASCADE);
DELETE FROM sqlite_sequence;
COMMIT;
